import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import Base_url from "../components/Base_url";

const OfficerDashboardPage = () => {
  const navigate = useNavigate();

  const [complaints, setComplaints] = useState([]);
  const [filteredComplaints, setFilteredComplaints] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [processingId, setProcessingId] = useState(null);

  const [stats, setStats] = useState({
    total: 0,
    pending: 0,
    inProgress: 0,
    resolved: 0,
    critical: 0,
  });

  const [filters, setFilters] = useState({
    status: "all",
    priority: "all",
    urgent: "all",
    search: "",
  });

  /* ---------------- AUTH GUARD ---------------- */
  useEffect(() => {
    const token = localStorage.getItem("officer_token");
    if (!token) navigate("/officer/login");
  }, [navigate]);

  /* ---------------- FETCH COMPLAINTS ---------------- */
  useEffect(() => {
    const fetchComplaints = async () => {
      try {
        const token = localStorage.getItem("officer_token");
        const { data } = await axios.get(`${Base_url}/complaints`, {
          headers: { Authorization: `Bearer ${token}` },
        });

        setComplaints(data);
        setFilteredComplaints(data);
        calculateStats(data);
      } catch {
        setError("Failed to load complaints");
      } finally {
        setLoading(false);
      }
    };

    fetchComplaints();
  }, []);

  /* ---------------- URGENT CHECK ---------------- */
  const isUrgent = (complaint) => {
    if (complaint.status === "RESOLVED") return false;

    const now = new Date();
    const createdAt = new Date(complaint.created_at);
    const diffHours = (now - createdAt) / (1000 * 60 * 60);

    return diffHours >= 48;
  };

  const getOutOfDateCount = () => {
    return complaints.filter(isUrgent).length;
  };

  /* ---------------- FILTER LOGIC ---------------- */
  useEffect(() => {
    let result = complaints;

    if (filters.status !== "all") {
      result = result.filter((c) => c.status === filters.status);
    }

    if (filters.priority !== "all") {
      result = result.filter((c) => c.priority_level === filters.priority);
    }

    if (filters.urgent === "yes") {
      result = result.filter(isUrgent);
    }

    if (filters.search) {
      const q = filters.search.toLowerCase();
      result = result.filter(
        (c) =>
          c.complaint_id.toLowerCase().includes(q) ||
          c.service_type.toLowerCase().includes(q) ||
          c.ai_category?.toLowerCase().includes(q) ||
          c.email.toLowerCase().includes(q)
      );
    }

    setFilteredComplaints(result);
  }, [filters, complaints]);

  /* ---------------- HELPERS ---------------- */
  const calculateStats = (data) => {
    setStats({
      total: data.length,
      pending: data.filter((c) => c.status === "ACTIVE").length,
      inProgress: data.filter((c) => c.status === "IN_PROGRESS").length,
      resolved: data.filter((c) => c.status === "RESOLVED").length,
      critical: data.filter((c) => c.priority_level === "CRITICAL").length,
    });
  };

  const handleFilterChange = (key, value) => {
    setFilters((prev) => ({ ...prev, [key]: value }));
  };

  const handleClearFilters = () => {
    setFilters({
      status: "all",
      priority: "all",
      urgent: "all",
      search: "",
    });
  };

  /* ---------------- STATUS UPDATE ---------------- */
  const handleStartInvestigation = async (complaintId) => {
    setProcessingId(complaintId);
    try {
      const token = localStorage.getItem("officer_token");

      await axios.patch(
        `${Base_url}/complaints/${complaintId}/status`,
        { status: "IN_PROGRESS" },
        { headers: { Authorization: `Bearer ${token}` } }
      );

      const updated = complaints.map((c) =>
        c.complaint_id === complaintId
          ? { ...c, status: "IN_PROGRESS" }
          : c
      );

      setComplaints(updated);
      calculateStats(updated);
      alert("Investigation started successfully!");
    } catch {
      alert("Failed to start investigation");
    } finally {
      setProcessingId(null);
    }
  };

  /* ---------------- UI HELPERS ---------------- */
  const formatDate = (d) =>
    new Date(d).toLocaleDateString("en-IN", {
      day: "2-digit",
      month: "short",
      year: "numeric",
    });

  /* ---------------- RENDER ---------------- */
  return (
    <div className="min-h-screen bg-gray-50 p-6">
      {/* FILTERS */}
      <div className="bg-white p-6 rounded-xl shadow mb-6">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <input
            placeholder="Search..."
            value={filters.search}
            onChange={(e) => handleFilterChange("search", e.target.value)}
            className="border p-3 rounded-xl"
          />

          <select
            value={filters.status}
            onChange={(e) => handleFilterChange("status", e.target.value)}
            className="border p-3 rounded-xl"
          >
            <option value="all">All Status</option>
            <option value="ACTIVE">Active</option>
            <option value="IN_PROGRESS">In Progress</option>
            <option value="RESOLVED">Resolved</option>
          </select>

          <select
            value={filters.priority}
            onChange={(e) => handleFilterChange("priority", e.target.value)}
            className="border p-3 rounded-xl"
          >
            <option value="all">All Priority</option>
            <option value="CRITICAL">Critical</option>
            <option value="HIGH">High</option>
            <option value="MEDIUM">Medium</option>
            <option value="LOW">Low</option>
          </select>

          <select
            value={filters.urgent}
            onChange={(e) => handleFilterChange("urgent", e.target.value)}
            className="border p-3 rounded-xl"
          >
            <option value="all">All</option>
            <option value="yes">Urgent (≥48 hrs)</option>
          </select>
        </div>

        <button
          onClick={handleClearFilters}
          className="mt-4 text-red-600 font-medium"
        >
          Clear Filters
        </button>
      </div>

      {/* TABLE */}
      <div className="bg-white rounded-xl shadow overflow-x-auto">
        {loading ? (
          <p className="p-6">Loading...</p>
        ) : filteredComplaints.length === 0 ? (
          <p className="p-6">No complaints found</p>
        ) : (
          <table className="w-full">
            <thead className="bg-gray-100">
              <tr>
                <th className="p-4 text-left">ID</th>
                <th className="p-4 text-left">Service</th>
                <th className="p-4 text-left">Status</th>
                <th className="p-4 text-left">Priority</th>
                <th className="p-4 text-left">Date</th>
                <th className="p-4 text-left">Action</th>
              </tr>
            </thead>
            <tbody>
              {filteredComplaints.map((c) => (
                <tr key={c.complaint_id} className="border-t">
                  <td className="p-4 font-mono">{c.complaint_id}</td>
                  <td className="p-4">{c.service_type}</td>
                  <td className="p-4">{c.status}</td>
                  <td className="p-4">{c.priority_level}</td>
                  <td className="p-4">{formatDate(c.created_at)}</td>
                  <td className="p-4">
                    {c.status === "ACTIVE" ? (
                      <button
                        disabled={processingId === c.complaint_id}
                        onClick={() => handleStartInvestigation(c.complaint_id)}
                        className="bg-purple-600 text-white px-4 py-2 rounded"
                      >
                        Start
                      </button>
                    ) : (
                      <button
                        onClick={() =>
                          navigate(`/officer/complaints/${c.complaint_id}`)
                        }
                        className="bg-blue-600 text-white px-4 py-2 rounded"
                      >
                        View
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {/* URGENT STAT */}
      <div className="mt-6 text-red-600 font-bold">
        Urgent Attention Needed: {getOutOfDateCount()}
      </div>
    </div>
  );
};

export default OfficerDashboardPage;
